function toText(v) { if (v == null) return ''; if (typeof v === 'string') return v; if (typeof v === 'number' || typeof v === 'boolean') return String(v); if (Array.isArray(v)) return v.map(toText).filter(Boolean).join(' '); if (typeof v === 'object') return toText(v.text ?? v.mensagem ?? v.content ?? v.body ?? v.caption ?? ''); return String(v); }
function pickCliente(input) { if (!input) return { nome: 'Cliente', telefone: '' }; if (typeof input === 'string') return { nome: input.trim() || 'Cliente', telefone: '' }; return { nome: String(input.nome || input.name || input.pushName || 'Cliente').trim() || 'Cliente', telefone: String(input.telefone || input.phone || input.phoneNumber || '').trim() }; }
const mensagem = toText(src.mensagem ?? src.mensagens ?? src.message ?? src.messages ?? src.text ?? src.body ?? '').replace(/\s+/g, ' ').trim();
if (!mensagem && !(src.media_url || src.mediaUrl || src.message?.mediaUrl || src.attachment?.url || src.image?.url)) throw new Error('Mensagem ou midia obrigatoria');
const clienteObj = pickCliente(src.cliente || src.customer || src.contact || null);
const telefone = String(src.cliente_telefone ?? src.telefone ?? src.phone ?? src.phoneNumber ?? src.contact?.phoneNumber ?? clienteObj.telefone ?? src.from ?? '').replace(/\D/g, '');
const ticketId = String(src.ticket_id ?? src.ticket?.id ?? src.conversation_id ?? src.conversationId ?? src.chat_id ?? '').trim() || `WT-${Date.now()}`;
const conversationId = String(src.conversation_id ?? src.conversationId ?? src.ticket?.conversationId ?? src.ticket?.id ?? ticketId).trim() || ticketId;
const eventId = String(src.event_id ?? src.eventId ?? src.message_id ?? src.messageId ?? src.externalId ?? `evt-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`).trim();
const organizationId = String(src.organization_id ?? src.organizationId ?? src.tenant_id ?? src.tenantId ?? 'org_willtalk').trim();
const mediaUrl = src.media_url ?? src.mediaUrl ?? src.message?.mediaUrl ?? src.attachment?.url ?? src.image?.url ?? null;
const mimeType = src.mime_type ?? src.mimeType ?? src.message?.mimeType ?? src.attachment?.mime_type ?? src.image?.mime_type ?? null;
