const n = $('2. Normalizar Payload').item.json;
const wt = $json || {};
const meta = wt.metadata || wt.metadados || wt.conversation?.metadata || n.raw?.metadata || {};
function bool(v, d = false) { if (typeof v === 'boolean') return v; if (v == null || v === '') return d; return ['true', '1', 'sim', 'yes'].includes(String(v).toLowerCase()); }
function num(v, d = 0) { const x = Number(v); return Number.isFinite(x) ? x : d; }
function strOrNull(v) { const s = String(v ?? '').trim(); return s || null; }
const rawQueues = wt.queues || wt.filas || wt.filas_disponiveis_json || wt.availableQueues || n.raw?.queues || n.raw?.filas || n.raw?.filas_disponiveis_json || [];
let queues = Array.isArray(rawQueues) ? rawQueues.map((q, i) => ({ id: String(q.id ?? q.queue_id ?? q.queueId ?? `fila-${i + 1}`), name: String(q.name ?? q.nome ?? q.label ?? `Fila ${i + 1}`), menu_option: num(q.menu_option ?? q.menuOption ?? q.option ?? i + 1, i + 1), default_sla_mins: num(q.default_sla_mins ?? q.defaultSlaMins ?? q.sla_mins ?? q.slaMins, 30), is_active: q.is_active ?? q.isActive ?? true })).filter((q) => q.id && q.name) : [];
