return [{ json: { ...n, willtalk_state: wt, queues, conversation, orchestrator_payload: { platform: 'willtalk', organization_id: n.organization_id, event_id: n.event_id, conversation_id: n.conversation_id, cliente: n.cliente, mensagem: n.mensagem, media_url: n.media_url, mime_type: n.mime_type, business_hours_open: bool(n.business_hours_open, true), conversation, queues } } }];

const n = $('5. Preparar Payload Orquestrador').item.json;
const out = $json || {};
const failed = Boolean(out.error || out.statusCode >= 400 || (out.message && String(out.message).toLowerCase().includes('error')));
const safe = failed ? { reply_text: 'Nao consegui processar sua mensagem agora. Vou encaminhar para um atendente continuar por aqui.', triage_completed: true, menu_attempts: n.conversation.menu_attempts || 0, queue_id: n.conversation.queue_id || null, reason: 'orchestrator_error', agent_handoff_summary: `Falha ao consultar o Cerebro no fluxo n8n v5. Cliente: ${n.cliente.nome} (${n.cliente.telefone}). Mensagem: ${n.mensagem}` } : out;
